/**
 * Evolution Engine — 每日自动分析触发器
 *
 * 在 session_start 中异步触发，每天最多运行一次完整的分析流程。
 * Fire-and-forget：不阻塞 session 初始化。
 *
 * 流程：检查报告 → 获取锁 → 运行 analyzer → summarizer → Judge
 *       → 生成 Markdown 报告 → 合并 pending → 释放锁
 */

import {
	existsSync,
	writeFileSync,
	readFileSync,
	unlinkSync,
	statSync,
	renameSync,
	mkdirSync,
} from "node:fs";
import { homedir } from "node:os";
import { join } from "node:path";
import { execFile } from "node:child_process";

import type { Dirs, JudgeInput, EvolutionSuggestion } from "./types";
import {
	mergePending,
	saveLastRunStatus,
	loadMetricsHistory,
	loadHistory,
} from "./state";
import { generateDailyReport } from "./report-generator";
import { summarizeReport } from "./summarizer.js";
import { buildEffectReview } from "./effect-tracker.js";
import { runJudge } from "./judge";
import { runGc } from "./gc.js";

// ── 常量 ─────────────────────────────────────────────

/** analyzer 脚本执行超时 */
const ANALYZER_TIMEOUT_MS = 60_000;

const ANALYZER_SCRIPT = join(
	homedir(),
	".pi/agent/scripts/pi-session-analyzer/analyze.py",
);

// ── Lock 管理 ────────────────────────────────────────

interface LockData {
	pid: number;
	timestamp: string;
}

/**
 * 尝试获取锁文件。
 * - 已有锁但 PID 已死 → 清理 stale lock，获取新锁
 * - 已有锁且 PID 存活 → 返回 false
 * - 无锁文件 → 创建并返回 true
 *
 * 注意：使用 mkdirSync 作为原子操作（POSIX 上 mkdir 是原子的），
 * 避免 existsSync → writeFileSync 之间的 TOCTOU 竞态。
 */
function acquireLock(lockPath: string): boolean {
	if (existsSync(lockPath)) {
		try {
			const raw = readFileSync(lockPath, "utf-8");
			const lock = JSON.parse(raw) as LockData;

			// 检查 PID 是否仍然存活
			// process.kill(pid, 0) 不发送信号，只检查进程存在性
			try {
				process.kill(lock.pid, 0);
				// PID 仍然存活 → 另一个进程在运行
				return false;
			} catch {
				// PID 已死 → stale lock，清理
				unlinkSync(lockPath);
			}
		} catch {
			// 锁文件损坏 → 清理
			unlinkSync(lockPath);
		}
	}

	// 创建新锁
	const data: LockData = { pid: process.pid, timestamp: new Date().toISOString() };
	writeFileSync(lockPath, JSON.stringify(data, null, 2), "utf-8");
	return true;
}

/** 释放锁文件 */
function releaseLock(lockPath: string): void {
	try {
		unlinkSync(lockPath);
	} catch {
		// 锁文件可能已被其他进程清理
	}
}

// ── Pipeline 步骤 ────────────────────────────────────

/** 运行 Python analyzer 生成原始报告 */
function runAnalyzer(outputPath: string): Promise<string> {
	return new Promise<string>((resolve, reject) => {
		if (!existsSync(ANALYZER_SCRIPT)) {
			reject(new Error(`Session analyzer not found at ${ANALYZER_SCRIPT}`));
			return;
		}

		execFile(
			"python3",
			[ANALYZER_SCRIPT, "--since", "1d", "--format", "json", "--output", outputPath],
			{ timeout: ANALYZER_TIMEOUT_MS },
			(err: Error | null) => {
				if (err) {
					reject(err);
				} else {
					resolve(outputPath);
				}
			},
		);
	});
}

/**
 * 执行完整分析 pipeline（analyzer → summarizer → judge）。
 * 调用方负责 lock 管理。
 */
async function executePipeline(
	dirs: Dirs,
	today: string,
	reportPath: string,
): Promise<void> {
	// 确保 tmp 目录存在
	if (!existsSync(dirs.tmpDir)) {
		mkdirSync(dirs.tmpDir, { recursive: true });
	}

	// 1. 运行 analyzer
	const tmpReportPath = join(dirs.tmpDir, `daily-raw-${today}.json`);
	await runAnalyzer(tmpReportPath);

	// 2. 读取原始报告
	const rawReport = readFileSync(tmpReportPath, "utf-8");
	const report = JSON.parse(rawReport) as Record<string, unknown>;

	// 3. Summarizer pipeline
	const metricsHistory = loadMetricsHistory(dirs.evolutionDir);
	const signalReport = summarizeReport(
		report,
		metricsHistory,
		dirs.evolutionDir,
		tmpReportPath,
	);
	metricsHistory.push(signalReport.metricsSnapshot);

	// 3b. Effect review
	const recentHistory = loadHistory(dirs.evolutionDir, 30);
	const effectReview = buildEffectReview(recentHistory, metricsHistory);
	if (effectReview.length > 0) {
		signalReport.effectReview = effectReview;
	}

	// 4. 运行 LLM Judge（在 GC 之前，避免新信号文件被删除）
	const signalPath = join(
		dirs.signalsDir,
		`signal-${signalReport.metricsSnapshot.date}.json`,
	);
	const judgeInput: JudgeInput = {
		target: "all",
		reportPath: signalPath,
		promptFilePath: "",
	};

	let suggestions: EvolutionSuggestion[];
	try {
		suggestions = await runJudge(judgeInput, dirs.templateDir);
	} catch (err) {
		const msg = err instanceof Error ? err.message : String(err);
		throw new Error(`LLM Judge failed: ${msg}`);
	}

	// 5. GC（在 Judge 成功后执行，避免误删）
	runGc(dirs.evolutionDir);

	// 6. 生成 Markdown 报告 + 原子写入
	const markdown = generateDailyReport(signalReport, suggestions, effectReview);
	const tmpReport = `${reportPath}.tmp`;
	writeFileSync(tmpReport, markdown, "utf-8");
	renameSync(tmpReport, reportPath);

	// 7. 合并建议到 pending.json
	mergePending(dirs.evolutionDir, suggestions);

	// 8. 记录成功状态
	saveLastRunStatus(dirs.dailyReportsDir, "success");

	// 9. 清理临时原始报告
	try {
		unlinkSync(tmpReportPath);
	} catch {
		// 临时文件清理失败不影响主流程
	}
}

// ── 公共 API ─────────────────────────────────────────

/**
 * 每日自动分析入口。
 * 在 session_start 中调用，fire-and-forget。
 * 同一天只运行一次（通过文件存在性判断）。
 */
export async function checkAndRunDailyAnalysis(dirs: Dirs): Promise<void> {
	const today = new Date().toISOString().slice(0, 10);
	const reportPath = join(dirs.dailyReportsDir, `${today}.md`);

	// AC-2: 同一天不重复生成
	if (existsSync(reportPath) && statSync(reportPath).size > 0) {
		return;
	}

	// 获取锁
	const lockPath = join(dirs.dailyReportsDir, ".daily-report.lock");
	if (!acquireLock(lockPath)) {
		return;
	}

	try {
		await executePipeline(dirs, today, reportPath);
	} catch (err) {
		// AC-8: 失败不阻塞
		const msg = err instanceof Error ? err.message : String(err);
		console.error(`[evolve] Daily analysis failed: ${msg}`);
		saveLastRunStatus(dirs.dailyReportsDir, "failed", msg);
	} finally {
		releaseLock(lockPath);
	}
}

/**
 * Evolution Engine — 每日报告生成器
 *
 * 将 SignalReport + Suggestions + EffectReview 转换为人类可读的 Markdown 报告。
 */

import type { SignalReport, EvolutionSuggestion, EffectReview } from "./types";

// ── 公共 API ─────────────────────────────────────────

/**
 * 生成每日分析报告的 Markdown 文本。
 * 报告结构：数据概览 → 异常信号 → 趋势变化 → 改进建议 → 效果回顾（条件章节）
 */
export function generateDailyReport(
	signalReport: SignalReport,
	suggestions: EvolutionSuggestion[],
	effectReview?: EffectReview[],
): string {
	const date = new Date(signalReport.generatedAt).toISOString().slice(0, 10);
	const snapshot = signalReport.metricsSnapshot;
	const hasData = snapshot.sessionCount > 0;

	const sections: string[] = [
		`# Evolution Daily Report — ${date}`,
		"",
		"## 数据概览",
		...buildOverview(snapshot, hasData),
		"",
		"## 异常信号",
		...buildAnomalies(signalReport.anomalies),
		"",
		"## 趋势变化",
		...buildTrends(signalReport.trends),
		"",
		"## 改进建议",
		...buildSuggestions(suggestions),
	];

	// 效果回顾：仅有数据时追加
	if (effectReview && effectReview.length > 0) {
		sections.push("", "## 效果回顾", ...buildEffectReview(effectReview));
	}

	return sections.join("\n");
}

// ── 内部格式化函数 ───────────────────────────────────

function buildOverview(
	snapshot: { sessionCount: number; totalToolCalls: number; totalInputTokens: number; totalOutputTokens: number; avgTurnsPerSession: number },
	hasData: boolean,
): string[] {
	if (!hasData) {
		return [
			"- Session 数量：无数据",
			"- 工具调用总数：无数据",
			"- Token 消耗：无数据",
			"- 平均每 session 轮次：无数据",
		];
	}

	return [
		`- Session 数量：${snapshot.sessionCount}`,
		`- 工具调用总数：${snapshot.totalToolCalls}`,
		`- Token 消耗：input ${snapshot.totalInputTokens.toLocaleString()} / output ${snapshot.totalOutputTokens.toLocaleString()}`,
		`- 平均每 session 轮次：${formatNum(snapshot.avgTurnsPerSession)}`,
	];
}

function buildAnomalies(anomalies: Array<{ severity: string; detail: string }>): string[] {
	if (anomalies.length === 0) {
		return ["无异常"];
	}

	return anomalies.map(a => `- [${a.severity.toUpperCase()}] ${a.detail}`);
}

function buildTrends(trends: Array<{ field: string; previous: number; current: number; changePercent: number }>): string[] {
	if (trends.length === 0) {
		return ["无显著变化"];
	}

	return trends.map(t => {
		const sign = t.changePercent >= 0 ? "+" : "";
		return `- ${t.field}: ${formatNum(t.previous)} → ${formatNum(t.current)} (${sign}${t.changePercent.toFixed(1)}%)`;
	});
}

function buildSuggestions(suggestions: EvolutionSuggestion[]): string[] {
	if (suggestions.length === 0) {
		return ["系统运行良好，无需调整"];
	}

	const lines: string[] = [];
	for (let i = 0; i < suggestions.length; i++) {
		const s = suggestions[i];
		if (i > 0) lines.push("");
		lines.push(`### #${i} [${s.severity.toUpperCase()}] ${s.title}`);
		if (s.description) lines.push(`- 描述：${s.description}`);
		if (s.rationale) lines.push(`- 依据：${s.rationale}`);
		if (s.targetPath) lines.push(`- 修改目标：${s.targetPath}`);
		if (s.instruction) lines.push(`- 修改指令：${s.instruction}`);
	}
	return lines;
}

function buildEffectReview(reviews: EffectReview[]): string[] {
	return reviews.map(r => {
		const sign = r.changePercent >= 0 ? "+" : "";
		return `- ${r.suggestionTitle}: ${r.targetMetric} ${formatNum(r.before)} → ${formatNum(r.after)} (${sign}${r.changePercent.toFixed(1)}%)`;
	});
}

/** 格式化数字：整数直接显示，浮点保留 2 位，Infinity/NaN 显示为 "N/A" */
function formatNum(n: number): string {
	if (!Number.isFinite(n)) return "N/A";
	return Number.isInteger(n) ? String(n) : n.toFixed(2);
}

/**
 * Evolution Engine — 信号摘要器
 *
 * 将原始 Phase 2 报告（~745KB）压缩为 ~5KB 的 SignalReport，
 * 解决原始报告通过 CLI args 传给 pi 子进程导致 "Empty Judge output" 的问题。
 *
 * Pipeline: 原始报告 → extractMetricsSnapshot → detectAnomalies → computeTrends
 *           → buildEffectReview（如有历史）→ summarizeReport → stdin 传给 Judge
 */

import { writeFileSync } from "node:fs";
import { join } from "node:path";

import type {
	MetricsSnapshot,
	Anomaly,
	TrendDelta,
	SignalReport,
	EffectReview,
} from "./types.js";
import { saveMetricsSnapshot } from "./state.js";

// ── 指标提取 ─────────────────────────────────────────

/** 安全提取数字值，缺失或非数字时返回默认值 */
function safeNum(value: unknown, fallback: number = 0): number {
	return typeof value === "number" && Number.isFinite(value) ? value : fallback;
}

/** 从 report._meta 提取基础信息 */
function extractMetaInfo(report: Record<string, unknown>): { date: string; sessionCount: number } {
	const meta = report._meta as Record<string, unknown> | undefined;
	const sessionCount = safeNum(meta?.total_sessions);
	const analysisPeriod = meta?.analysis_period as Record<string, string> | undefined;
	const date = analysisPeriod?.until ?? new Date().toISOString().slice(0, 10);
	return { date, sessionCount };
}

/** 从 report 中提取 tool 和 error 相关指标 */
function extractToolMetrics(report: Record<string, unknown>): {
	totalToolCalls: number;
	editRetryRate: number;
	bashFailureRate: number;
	selfCorrectionRate: number;
	toolFailureRates: Record<string, number>;
} {
	const toolStats = report.tool_stats as Record<string, unknown> | undefined;
	const errorStats = report.error_stats as Record<string, unknown> | undefined;
	return {
		totalToolCalls: safeNum(toolStats?.total_calls),
		editRetryRate: safeNum(toolStats?.edit_retry_rate),
		bashFailureRate: safeNum(errorStats?.bash_failure_rate),
		selfCorrectionRate: safeNum(errorStats?.self_correction_rate),
		toolFailureRates: extractToolFailureRates(errorStats),
	};
}

/** 从 report 中提取 token 和 satisfaction 相关指标 */
function extractTokenAndSatisfactionMetrics(report: Record<string, unknown>): {
	totalInputTokens: number;
	totalOutputTokens: number;
	totalCost: number;
	avgInputPerSession: number;
	avgOutputPerSession: number;
	singleTurnCompletionRate: number;
	avgTurnsPerSession: number;
	avgToolCallsPerSession: number;
	medianSessionMinutes: number;
} {
	const tokenStats = report.token_stats as Record<string, unknown> | undefined;
	const avgPerSession = tokenStats?.avg_per_session as Record<string, unknown> | undefined;
	const satisfaction = report.satisfaction as Record<string, unknown> | undefined;
	const durationStats = satisfaction?.session_duration_stats as Record<string, unknown> | undefined;
	return {
		totalInputTokens: safeNum(tokenStats?.total_input),
		totalOutputTokens: safeNum(tokenStats?.total_output),
		totalCost: safeNum(tokenStats?.cost_total),
		avgInputPerSession: safeNum(avgPerSession?.input),
		avgOutputPerSession: safeNum(avgPerSession?.output),
		singleTurnCompletionRate: safeNum(satisfaction?.single_turn_completion_rate),
		avgTurnsPerSession: safeNum(satisfaction?.avg_turns_per_session),
		avgToolCallsPerSession: safeNum(satisfaction?.avg_tool_calls_per_session),
		medianSessionMinutes: safeNum(durationStats?.median_minutes),
	};
}

/** 从 report 中提取 user 和 skill 相关指标 */
function extractUserAndSkillMetrics(report: Record<string, unknown>): {
	userCorrectionRate: number;
	repeatedRequestCount: number;
	activeSkillCount: number;
	dormantSkillCount: number;
	totalSkillFileSize: number;
} {
	const userPatterns = report.user_patterns as Record<string, unknown> | undefined;
	const corrections = userPatterns?.corrections as Record<string, unknown> | undefined;
	const repeatedRequests = userPatterns?.repeated_requests as unknown[] | undefined;
	const skillStats = report.skill_stats as Record<string, unknown> | undefined;
	const triggeredSkills = skillStats?.triggered_skills as Record<string, unknown> | undefined;
	const neverTriggered = skillStats?.never_triggered as unknown[] | undefined;
	const skillFileSizes = skillStats?.skill_file_sizes as Record<string, number> | undefined;
	return {
		userCorrectionRate: safeNum(corrections?.rate),
		repeatedRequestCount: Array.isArray(repeatedRequests) ? repeatedRequests.length : 0,
		activeSkillCount: triggeredSkills ? Object.keys(triggeredSkills).length : 0,
		dormantSkillCount: Array.isArray(neverTriggered) ? neverTriggered.length : 0,
		totalSkillFileSize: skillFileSizes
			? Object.values(skillFileSizes).reduce((sum, size) => sum + size, 0)
			: 0,
	};
}

/**
 * 从原始报告提取结构化指标快照。
 * 报告结构由 usage-tracker 的 session analyzer 产出。
 */
export function extractMetricsSnapshot(
	report: Record<string, unknown>,
): MetricsSnapshot {
	const meta = extractMetaInfo(report);
	const tool = extractToolMetrics(report);
	const tokenSat = extractTokenAndSatisfactionMetrics(report);
	const userSkill = extractUserAndSkillMetrics(report);

	return {
		date: meta.date,
		sessionCount: meta.sessionCount,
		totalToolCalls: tool.totalToolCalls,
		toolFailureRates: tool.toolFailureRates,
		editRetryRate: tool.editRetryRate,
		bashFailureRate: tool.bashFailureRate,
		singleTurnCompletionRate: tokenSat.singleTurnCompletionRate,
		avgTurnsPerSession: tokenSat.avgTurnsPerSession,
		avgToolCallsPerSession: tokenSat.avgToolCallsPerSession,
		selfCorrectionRate: tool.selfCorrectionRate,
		totalInputTokens: tokenSat.totalInputTokens,
		totalOutputTokens: tokenSat.totalOutputTokens,
		totalCost: tokenSat.totalCost,
		avgInputPerSession: tokenSat.avgInputPerSession,
		avgOutputPerSession: tokenSat.avgOutputPerSession,
		userCorrectionRate: userSkill.userCorrectionRate,
		repeatedRequestCount: userSkill.repeatedRequestCount,
		medianSessionMinutes: tokenSat.medianSessionMinutes,
		activeSkillCount: userSkill.activeSkillCount,
		dormantSkillCount: userSkill.dormantSkillCount,
		totalSkillFileSize: userSkill.totalSkillFileSize,
	};
}

/** 从 error_stats.by_tool 提取失败率 > 0.05 的工具 */
function extractToolFailureRates(
	errorStats: Record<string, unknown> | undefined,
): Record<string, number> {
	const rates: Record<string, number> = {};
	if (!errorStats || typeof errorStats.by_tool !== "object" || !errorStats.by_tool) {
		return rates;
	}

	const byTool = errorStats.by_tool as Record<string, Record<string, unknown>>;
	for (const [tool, data] of Object.entries(byTool)) {
		const errorRate = typeof data.error_rate === "number" ? data.error_rate : 0;
		// 只保留值得关注的高失败率工具
		if (errorRate > 0.05) {
			rates[tool] = errorRate;
		}
	}
	return rates;
}

// ── 压缩工具 ─────────────────────────────────────────

/** 保留 items 数组中前 N 项，丢弃其余 */
export function compressTopN(
	items: Array<Record<string, unknown>>,
	n: number,
): Array<Record<string, unknown>> {
	return items.slice(0, n);
}

/** 按 metricKey 降序排列后保留前 N 项 */
export function compressByProject(
	items: Array<Record<string, unknown>>,
	metricKey: string,
	topN: number,
): Array<Record<string, unknown>> {
	return [...items]
		.sort((a, b) => {
			const va = typeof a[metricKey] === "number" ? a[metricKey] as number : 0;
			const vb = typeof b[metricKey] === "number" ? b[metricKey] as number : 0;
			return vb - va;
		})
		.slice(0, topN);
}

// ── 异常检测 ─────────────────────────────────────────

/**
 * 从原始报告中检测异常信号。
 * 使用固定阈值，不依赖历史数据。
 */
export function detectAnomalies(
	report: Record<string, unknown>,
): Anomaly[] {
	const anomalies: Anomaly[] = [];

	// 工具失败率异常
	const errorStats = report.error_stats as Record<string, unknown> | undefined;
	const byTool = errorStats?.by_tool as Record<string, Record<string, unknown>> | undefined;
	if (byTool) {
		for (const [tool, data] of Object.entries(byTool)) {
			const rate = typeof data.error_rate === "number" ? data.error_rate : 0;
			if (rate >= 0.3) {
				anomalies.push({
					type: "tool_failure",
					detail: `Tool "${tool}" error rate ${(rate * 100).toFixed(1)}%`,
					severity: rate >= 0.5 ? "high" : "medium",
				});
			}
		}
	}

	// 沉睡 skill 异常
	const skillStats = report.skill_stats as Record<string, unknown> | undefined;
	const neverTriggered = skillStats?.never_triggered as string[] | undefined;
	if (Array.isArray(neverTriggered) && neverTriggered.length > 10) {
		anomalies.push({
			type: "dormant_skill",
			detail: `${neverTriggered.length} skills never triggered`,
			severity: neverTriggered.length > 20 ? "high" : "medium",
		});
	}

	// 用户纠正率异常
	const userPatterns = report.user_patterns as Record<string, unknown> | undefined;
	const corrections = userPatterns?.corrections as Record<string, unknown> | undefined;
	const correctionRate = typeof corrections?.rate === "number" ? corrections.rate : 0;
	if (correctionRate > 0.3) {
		anomalies.push({
			type: "user_correction",
			detail: `User correction rate ${(correctionRate * 100).toFixed(1)}%`,
			severity: correctionRate > 0.5 ? "high" : "medium",
		});
	}

	// Token 热点（单项目消耗异常高）
	const tokenStats = report.token_stats as Record<string, unknown> | undefined;
	const hotspots = tokenStats?.hotspots as Array<Record<string, unknown>> | undefined;
	if (Array.isArray(hotspots)) {
		for (const spot of hotspots.slice(0, 3)) {
			const input = typeof spot.input === "number" ? spot.input : 0;
			if (input > 5_000_000) {
				anomalies.push({
					type: "token_hotspot",
					detail: `Project "${spot.project ?? "unknown"}" consumed ${(input / 1_000_000).toFixed(1)}M input tokens`,
					severity: input > 20_000_000 ? "high" : "medium",
				});
			}
		}
	}

	return anomalies;
}

// ── 趋势计算 ─────────────────────────────────────────

/** 需要对比的数值字段及其合理范围 */
const COMPARABLE_FIELDS: Array<{ key: keyof MetricsSnapshot; direction: "lower_better" | "higher_better" }> = [
	{ key: "editRetryRate", direction: "lower_better" },
	{ key: "bashFailureRate", direction: "lower_better" },
	{ key: "singleTurnCompletionRate", direction: "higher_better" },
	{ key: "userCorrectionRate", direction: "lower_better" },
	{ key: "selfCorrectionRate", direction: "higher_better" },
	{ key: "avgTurnsPerSession", direction: "lower_better" },
];

/**
 * 对比当前与上一个 snapshot 的关键指标变化。
 * 只返回变化超过 10% 的指标。
 */
export function computeTrends(
	current: MetricsSnapshot,
	previous: MetricsSnapshot,
): TrendDelta[] {
	const deltas: TrendDelta[] = [];

	for (const { key } of COMPARABLE_FIELDS) {
		const prev = previous[key] as number;
		const curr = current[key] as number;
		if (prev === 0 && curr === 0) continue;

		const changePercent = prev === 0
			? (curr === 0 ? 0 : 100)
			: ((curr - prev) / prev) * 100;

		// 只关注变化超过 10% 的指标
		if (Math.abs(changePercent) >= 10) {
			deltas.push({
				field: key,
				previous: prev,
				current: curr,
				changePercent: Math.round(changePercent * 100) / 100,
			});
		}
	}

	return deltas;
}

// ── 原始报告压缩 ─────────────────────────────────────

/**
 * 从原始报告中提取 Judge 需要的关键子集。
 * 保留 actionable_issues 和 skill_health 的 top-N，
 * 保留 by_project 的 top-5，丢弃冗余的 raw 数据。
 */
function compressReport(report: Record<string, unknown>): Record<string, unknown> {
	const result: Record<string, unknown> = {};

	// _meta 保留
	if (report._meta) result._meta = report._meta;

	// actionable_issues 保留前 5
	const issues = report.actionable_issues as Array<Record<string, unknown>> | undefined;
	if (Array.isArray(issues)) {
		result.actionable_issues = compressTopN(issues, 5);
	}

	// skill_health 保留前 10
	const skillHealth = report.skill_health as Array<Record<string, unknown>> | undefined;
	if (Array.isArray(skillHealth)) {
		result.skill_health = compressTopN(skillHealth, 10);
	}

	// satisfaction.by_project 保留 top-5 sessions
	const satisfaction = report.satisfaction as Record<string, unknown> | undefined;
	const byProject = satisfaction?.by_project as Array<Record<string, unknown>> | undefined;
	if (Array.isArray(byProject)) {
		result.satisfaction_top_projects = compressByProject(byProject, "sessions", 5);
	}

	// error_stats 的摘要（只保留聚合指标，去掉详细数据）
	if (report.error_stats && typeof report.error_stats === "object") {
		const {
			by_project: _bp,
			by_tool: _bt,
			top_error_patterns: _tep,
			...errorSummary
		} = report.error_stats as Record<string, unknown> & {
			by_project?: unknown;
			by_tool?: unknown;
			top_error_patterns?: unknown;
		};
		result.error_stats_summary = errorSummary;
	}

	// top_error_patterns 保留前 3
	const errorStats = report.error_stats as Record<string, unknown> | undefined;
	const topPatterns = errorStats?.top_error_patterns as unknown[] | undefined;
	if (Array.isArray(topPatterns)) {
		result.top_error_patterns = topPatterns.slice(0, 3);
	}

	return result;
}

// ── 主入口 ───────────────────────────────────────────

/**
 * 将原始报告压缩为 SignalReport 并持久化。
 * 返回 SignalReport 路径供 Judge stdin 消费。
 */
export function summarizeReport(
	report: Record<string, unknown>,
	metricsHistory: MetricsSnapshot[],
	evolutionDir: string,
	reportPath: string,
): SignalReport {
	// 1. 提取指标快照
	const snapshot = extractMetricsSnapshot(report);

	// 2. 检测异常
	const anomalies = detectAnomalies(report);

	// 3. 计算趋势（需要历史数据）
	let trends: TrendDelta[] = [];
	const previous = metricsHistory.length > 0
		? metricsHistory[metricsHistory.length - 1]
		: undefined;
	if (previous) {
		trends = computeTrends(snapshot, previous);
	}

	// 4. 效果回顾（由 commands.ts 在外部通过 effect-tracker.buildEffectReview 计算）
	const effectReview: EffectReview[] | undefined = undefined;

	// 5. 压缩原始报告
	const compressed = compressReport(report);

	// 6. 组装 SignalReport
	const signalReport: SignalReport = {
		generatedAt: new Date().toISOString(),
		reportPath,
		metricsSnapshot: snapshot,
		anomalies,
		trends,
		effectReview: effectReview,
		compressed,
	};

	// 7. 持久化 snapshot
	saveMetricsSnapshot(evolutionDir, snapshot);

	// 8. 写入信号文件
	const signalPath = join(
		evolutionDir,
		"signals",
		`signal-${snapshot.date}.json`,
	);
	writeFileSync(signalPath, JSON.stringify(signalReport, null, 2), "utf-8");

	return signalReport;
}

/**
 * Evolution Engine — 效果追踪器
 *
 * 对比已应用建议前后的 metrics snapshot 变化，
 * 产出 EffectReview 供 Judge 在下次分析时参考。
 *
 * 匹配逻辑：启发式地将 suggestion title 中的关键词映射到 metric 字段名。
 * 无匹配 → 返回空数组，Judge 不会收到效果回顾。
 */

import type {
	HistoryEntry,
	MetricsSnapshot,
	EffectReview,
} from "./types.js";

// ── 关键词 → metric 字段映射 ─────────────────────────

/** suggestion title 中的关键词到 MetricsSnapshot 字段名的启发式映射 */
const KEYWORD_TO_METRIC: Array<{ keywords: string[]; field: keyof MetricsSnapshot }> = [
	{ keywords: ["edit", "retry", "匹配"], field: "editRetryRate" },
	{ keywords: ["bash", "failure", "失败"], field: "bashFailureRate" },
	{ keywords: ["single-turn", "单轮", "completion"], field: "singleTurnCompletionRate" },
	{ keywords: ["correction", "纠正", "用户纠正"], field: "userCorrectionRate" },
	{ keywords: ["self-correction", "自纠正", "self_correction"], field: "selfCorrectionRate" },
	{ keywords: ["turns", "轮次", "avg_turns"], field: "avgTurnsPerSession" },
	{ keywords: ["token", "input", "输入"], field: "totalInputTokens" },
	{ keywords: ["token", "output", "输出"], field: "totalOutputTokens" },
	{ keywords: ["cost", "成本", "花费"], field: "totalCost" },
	{ keywords: ["dormant", "沉睡", "未触发"], field: "dormantSkillCount" },
	{ keywords: ["skill", "技能"], field: "activeSkillCount" },
];

/** 从 suggestion title 中匹配最相关的 metric 字段 */
function matchMetricField(title: string): keyof MetricsSnapshot | null {
	const lower = title.toLowerCase();
	for (const mapping of KEYWORD_TO_METRIC) {
		// 所有关键词都出现在 title 中才算匹配
		if (mapping.keywords.every(kw => lower.includes(kw.toLowerCase()))) {
			return mapping.field;
		}
	}
	// 降级：任一关键词匹配
	for (const mapping of KEYWORD_TO_METRIC) {
		if (mapping.keywords.some(kw => lower.includes(kw.toLowerCase()))) {
			return mapping.field;
		}
	}
	return null;
}

// ── 时间窗口 ─────────────────────────────────────────

function isWithinDays(isoTimestamp: string, days: number): boolean {
	const then = new Date(isoTimestamp).getTime();
	if (Number.isNaN(then)) return false;
	return Date.now() - then < days * 24 * 60 * 60 * 1000;
}

// ── Snapshot 查找 ────────────────────────────────────

/**
 * 找到指定日期或之前最近的 snapshot。
 * metricsHistory 按 date 升序排列。
 */
function findSnapshotBefore(
	metricsHistory: MetricsSnapshot[],
	date: string,
): MetricsSnapshot | null {
	const target = new Date(date).getTime();
	if (Number.isNaN(target)) return null;

	let best: MetricsSnapshot | null = null;
	for (const snapshot of metricsHistory) {
		const t = new Date(snapshot.date).getTime();
		if (Number.isNaN(t)) continue;
		if (t <= target) {
			best = snapshot;
		} else {
			break;
		}
	}
	return best;
}

/** 找到最新的 snapshot */
function findLatestSnapshot(
	metricsHistory: MetricsSnapshot[],
): MetricsSnapshot | null {
	if (metricsHistory.length === 0) return null;
	return metricsHistory[metricsHistory.length - 1];
}

// ── 公共 API ─────────────────────────────────────────

/**
 * 为最近 7 天内的 apply 操作构建效果回顾。
 *
 * @param recentHistory - 最近的 history entries（建议调用方传最近 30 条）
 * @param metricsHistory - metrics 历史快照
 * @returns 效果回顾列表，无匹配时为空数组
 */
export function buildEffectReview(
	recentHistory: HistoryEntry[],
	metricsHistory: MetricsSnapshot[],
): EffectReview[] {
	if (metricsHistory.length === 0) return [];

	// 筛选最近 7 天的 apply 记录
	const recentApplies = recentHistory.filter(
		entry => entry.action === "apply" && isWithinDays(entry.timestamp, 7),
	);

	if (recentApplies.length === 0) return [];

	const latest = findLatestSnapshot(metricsHistory);
	if (!latest) return [];

	const reviews: EffectReview[] = [];

	for (const entry of recentApplies) {
		const field = matchMetricField(entry.title);
		if (!field) continue;

		// 找到 apply 之前的 snapshot
		const beforeSnapshot = entry.metricsSnapshotDate
			? findSnapshotBefore(metricsHistory, entry.metricsSnapshotDate)
			: findSnapshotBefore(metricsHistory, entry.timestamp);

		if (!beforeSnapshot) continue;

		const before = beforeSnapshot[field] as number;
		const after = latest[field] as number;

		if (typeof before !== "number" || typeof after !== "number") continue;
		if (before === 0 && after === 0) continue;

		const changePercent = before === 0
			? 100
			: Math.round(((after - before) / before) * 10000) / 100;

		reviews.push({
			suggestionTitle: entry.title,
			appliedAt: entry.timestamp,
			targetMetric: field,
			before,
			after,
			changePercent,
		});
	}

	return reviews;
}

/**
 * Evolution Engine — 数据垃圾回收
 *
 * 清理过期的 reports、signals、daily 数据文件，防止磁盘无限膨胀。
 * 由 /evolve 命令在每次运行后自动调用。
 */

import { existsSync, readdirSync, unlinkSync, statSync } from "node:fs";
import { join } from "node:path";

// ── GC 策略常量 ──────────────────────────────────────

/** reports/*.json 保留最新 N 个 */
const MAX_REPORTS = 3;

/** signals/*.json 保留最新 N 个 */
const MAX_SIGNALS = 30;

/** daily/*.json 保留天数 */
const MAX_DAILY_DAYS = 90;

/** daily-reports/*.md 保留天数 */
const MAX_DAILY_REPORT_DAYS = 30;

// ── 辅助函数 ─────────────────────────────────────────

/** 安全地按修改时间降序排列目录中的 .json 文件 */
function listJsonByMtime(dir: string): string[] {
	if (!existsSync(dir)) return [];

	try {
		const entries = readdirSync(dir);
		return entries
			.filter(name => name.endsWith(".json"))
			.map(name => ({
				name,
				path: join(dir, name),
				mtime: statSync(join(dir, name)).mtimeMs,
			}))
			.sort((a, b) => b.mtime - a.mtime)
			.map(e => e.path);
	} catch {
		return [];
	}
}

/** 删除指定文件路径列表 */
function removeFiles(paths: string[]): number {
	let removed = 0;
	for (const p of paths) {
		try {
			unlinkSync(p);
			removed++;
		} catch (err) {
			// 文件可能已被其他进程删除，记录但不停滞
			console.warn(`[evolve-gc] Failed to remove ${p}: ${err instanceof Error ? err.message : String(err)}`);
		}
	}
	return removed;
}

/** 从 daily 文件名提取日期并过滤超过 N 天的 */
function listExpiredDaily(dir: string, maxDays: number): string[] {
	if (!existsSync(dir)) return [];

	const cutoff = Date.now() - maxDays * 24 * 60 * 60 * 1000;

	try {
		const entries = readdirSync(dir);
		const expired: string[] = [];

		for (const name of entries) {
			if (!name.endsWith(".json")) continue;

			// daily 文件名格式: 2026-05-27.json
			const dateStr = name.replace(".json", "");
			const fileTime = new Date(dateStr).getTime();

			// 文件名无法解析为日期时，用 mtime 兜底
			const effectiveTime = Number.isNaN(fileTime)
				? statSync(join(dir, name)).mtimeMs
				: fileTime;

			if (effectiveTime < cutoff) {
				expired.push(join(dir, name));
			}
		}

		return expired;
	} catch {
		return [];
	}
}

/** 从 daily-reports 文件名提取日期并过滤超过 N 天的指定扩展名文件 */
function listExpiredDailyByExt(dir: string, maxDays: number, ext: string): string[] {
	if (!existsSync(dir)) return [];

	const cutoff = Date.now() - maxDays * 24 * 60 * 60 * 1000;

	try {
		const entries = readdirSync(dir);
		const expired: string[] = [];

		for (const name of entries) {
			// 排除 dotfile 和不匹配扩展名的文件
			if (!name.endsWith(ext) || name.startsWith(".")) continue;

			// 文件名格式: 2026-05-27.md
			const dateStr = name.replace(ext, "");
			const fileTime = new Date(dateStr).getTime();

			// 文件名无法解析为日期时，用 mtime 兜底
			const effectiveTime = Number.isNaN(fileTime)
				? statSync(join(dir, name)).mtimeMs
				: fileTime;

			if (effectiveTime < cutoff) {
				expired.push(join(dir, name));
			}
		}

		return expired;
	} catch {
		return [];
	}
}

// ── 公共 API ─────────────────────────────────────────

/** GC 清理结果 */
export interface GcResult {
	reportsRemoved: number;
	signalsRemoved: number;
	dailyRemoved: number;
	dailyReportsRemoved: number;
}

/**
 * 执行数据垃圾回收。
 * 目录不存在时静默跳过，不报错。
 */
export function runGc(evolutionDir: string): GcResult {
	const reportsDir = join(evolutionDir, "reports");
	const signalsDir = join(evolutionDir, "signals");
	const dailyDir = join(evolutionDir, "daily");

	// reports: 保留最新 MAX_REPORTS 个
	const reportFiles = listJsonByMtime(reportsDir);
	const reportsToRemove = reportFiles.slice(MAX_REPORTS);
	const reportsRemoved = removeFiles(reportsToRemove);

	// signals: 保留最新 MAX_SIGNALS 个
	const signalFiles = listJsonByMtime(signalsDir);
	const signalsToRemove = signalFiles.slice(MAX_SIGNALS);
	const signalsRemoved = removeFiles(signalsToRemove);

	// daily: 保留 MAX_DAILY_DAYS 天内
	const expiredDaily = listExpiredDaily(dailyDir, MAX_DAILY_DAYS);
	const dailyRemoved = removeFiles(expiredDaily);

	// daily-reports: 保留 MAX_DAILY_REPORT_DAYS 天内的 .md 文件
	let dailyReportsRemoved = 0;
	const dailyReportsDir = join(evolutionDir, "daily-reports");
	if (existsSync(dailyReportsDir)) {
		const expiredReports = listExpiredDailyByExt(dailyReportsDir, MAX_DAILY_REPORT_DAYS, ".md");
		dailyReportsRemoved = removeFiles(expiredReports);
	}

	return { reportsRemoved, signalsRemoved, dailyRemoved, dailyReportsRemoved };
}

/**
 * Evolution Engine — 状态持久化
 *
 * 管理 suggestions/pending.json 和 history.jsonl。
 * 所有路径基于传入的 evolutionDir 参数，不硬编码。
 */

import { existsSync, mkdirSync, readFileSync, writeFileSync, appendFileSync } from "node:fs";
import { join } from "node:path";
import type { PendingFile, HistoryEntry, MetricsSnapshot, EvolutionSuggestion } from "./types.js";

// ── 内部路径 ─────────────────────────────────────────

function suggestionsPath(dir: string): string {
	return join(dir, "suggestions", "pending.json");
}

function historyPath(dir: string): string {
	return join(dir, "history.jsonl");
}

function metricsHistoryPath(dir: string): string {
	return join(dir, "metrics-history.json");
}

// ── 公共 API ─────────────────────────────────────────

/**
 * 读取 pending.json。
 * 文件不存在或 JSON 损坏时返回 null。
 */
export function loadPending(dir: string): PendingFile | null {
	const filePath = suggestionsPath(dir);
	if (!existsSync(filePath)) return null;

	try {
		const raw = readFileSync(filePath, "utf-8");
		const pending = JSON.parse(raw) as PendingFile;

		// Migration: 旧格式有 diff 字段而无 instruction，自动迁移
		for (const sug of pending.suggestions) {
			if (!sug.instruction && (sug as unknown as Record<string, unknown>).diff) {
				sug.instruction = String((sug as unknown as Record<string, unknown>).diff);
				delete (sug as unknown as Record<string, unknown>).diff;
			}
		}

		return pending;
	} catch {
		return null;
	}
}

/**
 * 写入 pending.json。
 * 目录不存在时递归创建。
 */
export function savePending(dir: string, pending: PendingFile): void {
	const filePath = suggestionsPath(dir);
	const dirName = join(dir, "suggestions");

	if (!existsSync(dirName)) {
		mkdirSync(dirName, { recursive: true });
	}

	writeFileSync(filePath, JSON.stringify(pending, null, 2), "utf-8");
}

/**
 * 追加一条 JSON 行到 history.jsonl。
 * 文件不存在时创建。
 */
export function appendHistory(dir: string, entry: HistoryEntry): void {
	const filePath = historyPath(dir);

	appendFileSync(filePath, JSON.stringify(entry) + "\n", "utf-8");
}

/**
 * 读取 history.jsonl 最后 N 条记录。
 * 文件不存在返回空数组。
 */
// ── Metrics Snapshot 持久化 ─────────────────────────

/** metrics-history.json 的文件结构 */
interface MetricsHistoryFile {
	snapshots: MetricsSnapshot[];
}

const MAX_METRICS_SNAPSHOTS = 30;

/**
 * 读取 metrics 历史。文件不存在或损坏时返回空数组。
 */
export function loadMetricsHistory(dir: string): MetricsSnapshot[] {
	const filePath = metricsHistoryPath(dir);
	if (!existsSync(filePath)) return [];

	try {
		const raw = readFileSync(filePath, "utf-8");
		const data = JSON.parse(raw) as MetricsHistoryFile;
		return Array.isArray(data.snapshots) ? data.snapshots : [];
	} catch {
		return [];
	}
}

/**
 * 追加一条 snapshot，滑动窗口保留最近 30 条。
 */
export function saveMetricsSnapshot(dir: string, snapshot: MetricsSnapshot): void {
	const history = loadMetricsHistory(dir);
	history.push(snapshot);

	// 滑动窗口：超出上限时删除最老的
	if (history.length > MAX_METRICS_SNAPSHOTS) {
		history.splice(0, history.length - MAX_METRICS_SNAPSHOTS);
	}

	const filePath = metricsHistoryPath(dir);
	writeFileSync(
		filePath,
		JSON.stringify({ snapshots: history }, null, 2),
		"utf-8",
	);
}

// ── History JSONL ────────────────────────────────────

// ── Daily Report 状态 ──────────────────────────────

/** pending.json 中 pending 状态建议的最大数量 */
const MAX_PENDING_SUGGESTIONS = 30;

/**
 * 增量合并新建议到 pending.json。
 * - title 精确匹配去重：已有 pending 建议的 title 与新建议相同时跳过
 * - 容量保护：pending 状态的建议不超过 MAX_PENDING_SUGGESTIONS 条
 * - 无现有文件时创建新 PendingFile
 */
export function mergePending(dir: string, newSuggestions: EvolutionSuggestion[]): void {
	if (newSuggestions.length === 0) return;

	const existing = loadPending(dir);
	if (!existing) {
		const pending: PendingFile = {
			generatedAt: new Date().toISOString(),
			reportUsed: "daily-report",
			suggestions: newSuggestions,
		};
		savePending(dir, pending);
		return;
	}

	// title 去重：跳过与已有 pending 建议同名的
	const pendingTitles = new Set(
		existing.suggestions
			.filter(s => s.status === "pending")
			.map(s => s.title),
	);
	const unique = newSuggestions.filter(s => !pendingTitles.has(s.title));

	if (unique.length > 0) {
		existing.suggestions.push(...unique);
	}

	// 容量保护：超出时按数组顺序驱逐最早的 pending（先入先出）
	const pendingCount = existing.suggestions.filter(s => s.status === "pending").length;
	if (pendingCount > MAX_PENDING_SUGGESTIONS) {
		const overflow = pendingCount - MAX_PENDING_SUGGESTIONS;
		let evicted = 0;
		for (const sug of existing.suggestions) {
			if (sug.status === "pending" && evicted < overflow) {
				sug.status = "rejected";
				evicted++;
			}
		}
		console.warn(
			`[evolve] Auto-evicted ${evicted} pending suggestion(s) to maintain capacity cap of ${MAX_PENDING_SUGGESTIONS}`,
		);
	}

	savePending(dir, existing);
}

/**
 * 写入每日运行状态文件，供诊断。
 * 文件路径: {dailyReportsDir}/.last-run-status
 */
export function saveLastRunStatus(
	dailyReportsDir: string,
	status: "success" | "failed",
	errorSummary?: string,
): void {
	const filePath = join(dailyReportsDir, ".last-run-status");
	const data = {
		status,
		timestamp: new Date().toISOString(),
		...(errorSummary ? { errorSummary } : {}),
	};
	writeFileSync(filePath, JSON.stringify(data, null, 2), "utf-8");
}

// ── History JSONL ────────────────────────────────────

export function loadHistory(dir: string, limit: number = 10): HistoryEntry[] {
	const filePath = historyPath(dir);
	if (!existsSync(filePath)) return [];

	try {
		const raw = readFileSync(filePath, "utf-8").trim();
		if (raw.length === 0) return [];

		const lines = raw.split("\n");
		const tail = lines.slice(-limit);

		const entries: HistoryEntry[] = [];
		for (const line of tail) {
			const trimmed = line.trim();
			if (trimmed.length === 0) continue;
			try {
				const entry = JSON.parse(trimmed) as HistoryEntry;
				// Migration: 旧格式有 diff 字段而无 instruction
				if (!entry.instruction && (entry as unknown as Record<string, unknown>).diff) {
					entry.instruction = String((entry as unknown as Record<string, unknown>).diff);
					delete (entry as unknown as Record<string, unknown>).diff;
				}
				entries.push(entry);
			} catch {
				// 损坏行跳过
			}
		}
		return entries;
	} catch {
		return [];
	}
}

/**
 * Evolution Engine — 类型定义
 *
 * 所有 status/target/severity 使用联合字面量（不使用 enum），
 * 与项目其他 extension 保持一致。
 */

// ── 信号摘要 Pipeline ───────────────────────────────

/** 趋势指标快照，用于跨周期对比 */
export interface MetricsSnapshot {
	date: string;
	sessionCount: number;
	totalToolCalls: number;
	/** 只存 rate < 0.95 的工具，避免字典膨胀 */
	toolFailureRates: Record<string, number>;
	editRetryRate: number;
	bashFailureRate: number;
	singleTurnCompletionRate: number;
	avgTurnsPerSession: number;
	avgToolCallsPerSession: number;
	selfCorrectionRate: number;
	totalInputTokens: number;
	totalOutputTokens: number;
	totalCost: number;
	avgInputPerSession: number;
	avgOutputPerSession: number;
	userCorrectionRate: number;
	repeatedRequestCount: number;
	medianSessionMinutes: number;
	activeSkillCount: number;
	dormantSkillCount: number;
	totalSkillFileSize: number;
}

/** 单个指标的前后变化 */
export interface TrendDelta {
	field: string;
	previous: number;
	current: number;
	changePercent: number;
}

/** 异常信号 */
export interface Anomaly {
	type: "tool_failure" | "dormant_skill" | "user_correction" | "token_hotspot";
	detail: string;
	severity: "high" | "medium" | "low";
}

/** 已应用建议的效果回顾 */
export interface EffectReview {
	suggestionTitle: string;
	appliedAt: string;
	targetMetric: string;
	before: number;
	after: number;
	changePercent: number;
}

/** 压缩后的信号报告，~5KB，供 Judge 消费 */
export interface SignalReport {
	generatedAt: string;
	reportPath: string;
	metricsSnapshot: MetricsSnapshot;
	anomalies: Anomaly[];
	trends: TrendDelta[];
	effectReview?: EffectReview[];
	/** 压缩后的原始报告子集 */
	compressed: Record<string, unknown>;
}

// ── 核心数据模型 ─────────────────────────────────────

/** LLM Judge 产出的单条进化建议 */
export interface EvolutionSuggestion {
	/** UUID */
	id: string;
	/** 建议目标类型 */
	target: "claude-md" | "skill";
	/** 要修改的文件绝对路径 */
	targetPath: string;
	/** 严重程度 */
	severity: "high" | "medium" | "low";
	/** 0-1 置信度 */
	confidence: number;
	/** 建议标题 */
	title: string;
	/** 建议内容描述 */
	description: string;
	/** 数据支撑说明 */
	rationale: string;
	/** 自然语言修改指令，供 LLM 执行时参考 */
	instruction: string;
	/** 当前状态，初始值为 "pending" */
	status: "pending" | "approved" | "rejected" | "applied" | "failed";
}

/** 待审批的建议文件（suggestions/pending.json） */
export interface PendingFile {
	/** ISO timestamp — 生成时间 */
	generatedAt: string;
	/** 使用的 Phase 2 报告路径 */
	reportUsed: string;
	/** 建议列表 */
	suggestions: EvolutionSuggestion[];
}

/** 操作历史条目（history.jsonl 每行一条） */
export interface HistoryEntry {
	/** ISO timestamp */
	timestamp: string;
	/** 操作类型 */
	action: "apply" | "rollback";
	/** 对应 suggestion ID */
	suggestionId: string;
	/** 目标文件路径 */
	targetPath: string;
	/** 备份文件路径 */
	backupPath: string;
	/** 应用的 instruction（自然语言修改指令） */
	instruction: string;
	/** 建议标题（用于回滚展示） */
	title: string;
	/** apply 时的 git commit SHA，用于 rollback 时 git revert */
	commitSha?: string;
	/** apply 时对应的 metrics snapshot 日期，用于效果追踪 */
	metricsSnapshotDate?: string;
}

// ── 自动触发 ─────────────────────────────────────────

/** 自动触发规则命中标记 */
export interface AutoTriggerFlag {
	/** 触发规则 */
	rule: "token-decline" | "skill-dormant" | "error-spike";
	/** ISO timestamp — 触发时间 */
	triggeredAt: string;
	/** 具体数值描述 */
	detail: string;
}

// ── Judge 输入 ────────────────────────────────────────

/** LLM Judge 子进程的输入参数 */
export interface JudgeInput {
	/** 分析目标 */
	target: "all" | "claude-md" | "skills" | "merge-reviewer";
	/** Phase 2 JSON 报告路径 */
	reportPath: string;
	/** 构建的 prompt 临时文件路径 */
	promptFilePath: string;
