/**
 * 执行一次 pi 子进程调用，返回解析后的建议 + 原始输出。
 * 如果 parseJudgeOutput 抛错（包括 "Empty Judge output"），
 * 会在 result 中把 raw 和 stderr 带回来供上层判断是否重试。
 */
function runJudgeOnce(
	templateContent: string,
