	for (const item of parsed) {
		if (typeof item !== "object" || item === null) continue;

		const record = item as Record<string, unknown>;

		// 检查所有必需字段存在
		let hasAllKeys = true;
		for (const key of REQUIRED_KEYS) {
			if (record[key] === undefined || record[key] === null) {
